  3→// ---------------------------------------------------------------------------
  4→// Rule Predicates & Conditions
  5→// ---------------------------------------------------------------------------
  6→
  7→export type RulePredicate = {
  8→  field: string;
  9→  operator:
 10→    | "eq"
 11→    | "neq"
 12→    | "lt"
 13→    | "lte"
 14→    | "gt"
 15→    | "gte"
 16→    | "in"
 17→    | "not_in"
 18→    | "exists";
 19→  value: string | number | boolean | string[];
 20→};
 21→
 22→export type RuleCondition = RulePredicate | RulePredicate[];
 23→
 24→// ---------------------------------------------------------------------------
 25→// Policy Domain Types
 26→// ---------------------------------------------------------------------------
 27→
 28→export type PolicyRule = {
 29→  id: string;
 30→  condition: RuleCondition;
 31→  effect: "allow" | "deny";
 32→  priority: number;
 33→};
 34→
 35→export type PolicySelector = {
 36→  workspace?: string;
 37→  agent_role?: string;
 38→  resource?: string;
 39→};
 40→
 41→export type PolicyStatus =
 42→  | "draft"
 43→  | "testing"
 44→  | "active"
 45→  | "deprecated"
 46→  | "superseded";
 47→
 48→export type PolicyRecord = {
 49→  id: RecordId<"policy">;
 50→  title: string;
 51→  description?: string;
 52→  version: number;
 53→  status: PolicyStatus;
 54→  selector: PolicySelector;
 55→  rules: PolicyRule[];
 56→  human_veto_required: boolean;
 57→  max_ttl?: string;
 58→  created_by: RecordId<"identity">;
 59→  workspace: RecordId<"workspace">;
 60→  supersedes?: RecordId<"policy">;
 61→  created_at: Date;
 62→  updated_at?: Date;
 63→};
 64→
 65→// ---------------------------------------------------------------------------
 66→// Policy Trace (recorded on intent.evaluation)
 67→// ---------------------------------------------------------------------------
 68→
 69→export type PolicyTraceEntry = {
 70→  policy_id: string;
 71→  policy_version: number;
 72→  rule_id: string;
 73→  effect: "allow" | "deny";
 74→  matched: boolean;
 75→  priority: number;
 76→};
 77→
 78→// ---------------------------------------------------------------------------
 79→// Policy Gate Result (output of policy evaluation pipeline)
 80→// ---------------------------------------------------------------------------
 81→
 82→export type PolicyGateWarning = {
 83→  rule_id: string;
 84→  field: string;
 85→  policy_id: string;
 86→};
 87→
 88→export type PolicyGateResult =
 89→  | {
 90→      passed: true;
 91→      policy_trace: PolicyTraceEntry[];
 92→      human_veto_required: boolean;
 93→      warnings: PolicyGateWarning[];
 94→    }
 95→  | {
 96→      passed: false;
 97→      reason: string;
 98→      policy_trace: PolicyTraceEntry[];
 99→      deny_rule_id: string;
100→      warnings: PolicyGateWarning[];
101→    };
102→
103→// ---------------------------------------------------------------------------
104→// Intent Evaluation Context (input to policy gate)
105→// ---------------------------------------------------------------------------
106→
107→export type IntentEvaluationContext = {
108→  goal: string;
109→  reasoning: string;
110→  priority: number;
111→  action_spec: {
112→    provider: string;
113→    action: string;
