  1→import type { RecordId, Surreal } from "surrealdb";
  2→import type {
  3→  PolicyRecord,
  4→  PolicyRule,
  5→  PolicyGateResult,
  6→  PolicyTraceEntry,
  7→  PolicyGateWarning,
  8→  IntentEvaluationContext,
  9→} from "./types";
 10→import { evaluateCondition } from "./predicate-evaluator";
 11→import { loadActivePolicies } from "./policy-queries";
 12→
 13→// ---------------------------------------------------------------------------
 14→// Pipeline Types
 15→// ---------------------------------------------------------------------------
 16→
 17→type AnnotatedRule = {
 18→  policyId: string;
 19→  policyVersion: number;
 20→  humanVetoRequired: boolean;
 21→  rule: PolicyRule;
 22→};
 23→
 24→type EvaluatedRule = AnnotatedRule & {
 25→  matched: boolean;
 26→  warnings: PolicyGateWarning[];
 27→};
 28→
 29→type EvaluationResult = {
 30→  evaluatedRules: EvaluatedRule[];
 31→  denyMatched: boolean;
 32→  warnings: PolicyGateWarning[];
 33→};
 34→
 35→// ---------------------------------------------------------------------------
 36→// Pure Pipeline Functions
 37→// ---------------------------------------------------------------------------
 38→
 39→export const deduplicatePolicies = (
 40→  policies: PolicyRecord[],
 41→): PolicyRecord[] => {
 42→  const seen = new Set<string>();
 43→  const result: PolicyRecord[] = [];
 44→
 45→  for (const policy of policies) {
 46→    const id = policy.id.id as string;
 47→    if (!seen.has(id)) {
 48→      seen.add(id);
 49→      result.push(policy);
 50→    }
 51→  }
 52→
 53→  return result;
 54→};
 55→
 56→export const collectAndSortRules = (
 57→  policies: PolicyRecord[],
 58→): AnnotatedRule[] => {
 59→  const annotated = policies.flatMap((policy) =>
 60→    policy.rules.map((rule) => ({
 61→      policyId: policy.id.id as string,
 62→      policyVersion: policy.version,
 63→      humanVetoRequired: policy.human_veto_required,
 64→      rule,
 65→    })),
 66→  );
 67→
 68→  return annotated.sort((a, b) => b.rule.priority - a.rule.priority);
 69→};
 70→
 71→export const evaluateRulesAgainstContext = (
 72→  rules: AnnotatedRule[],
 73→  context: IntentEvaluationContext,
 74→): EvaluationResult => {
 75→  const contextRecord = context as unknown as Record<string, unknown>;
 76→  const evaluatedRules: EvaluatedRule[] = [];
 77→  const allWarnings: PolicyGateWarning[] = [];
 78→
 79→  for (const annotated of rules) {
 80→    const { matched, warnings } = evaluateCondition(
 81→      contextRecord,
 82→      annotated.rule.condition,
 83→      annotated.rule.id,
 84→      annotated.policyId,
 85→    );
 86→
 87→    allWarnings.push(...warnings);
 88→    evaluatedRules.push({ ...annotated, matched, warnings });
 89→
 90→    if (matched && annotated.rule.effect === "deny") {
 91→      return {
 92→        evaluatedRules,
 93→        denyMatched: true,
 94→        warnings: allWarnings,
 95→      };
 96→    }
 97→  }
 98→
 99→  return {
100→    evaluatedRules,
101→    denyMatched: false,
102→    warnings: allWarnings,
103→  };
104→};
105→
106→export const buildGateResult = (
107→  evaluatedRules: EvaluatedRule[],
108→  denyMatched: boolean,
109→  warnings: PolicyGateWarning[],
110→): PolicyGateResult => {
111→  const policyTrace: PolicyTraceEntry[] = evaluatedRules.map((entry) => ({
112→    policy_id: entry.policyId,
113→    policy_version: entry.policyVersion,
114→    rule_id: entry.rule.id,
115→    effect: entry.rule.effect,
116→    matched: entry.matched,
117→    priority: entry.rule.priority,
118→  }));
119→
120→  if (denyMatched) {
121→    const denyRule = evaluatedRules.find(
122→      (entry) => entry.matched && entry.rule.effect === "deny",
123→    );
124→    return {
125→      passed: false,
126→      reason: `Policy deny rule '${denyRule!.rule.id}' matched`,
127→      policy_trace: policyTrace,
128→      deny_rule_id: denyRule!.rule.id,
129→      warnings,
130→    };
131→  }
132→
133→  const humanVetoRequired = evaluatedRules.some(
134→    (entry) => entry.humanVetoRequired,
135→  );
136→
137→  return {
138→    passed: true,
139→    policy_trace: policyTrace,
140→    human_veto_required: humanVetoRequired,
141→    warnings,
142→  };
143→};
144→
145→// ---------------------------------------------------------------------------
146→// Composition Root (single effect boundary)
147→// ---------------------------------------------------------------------------
148→
149→export const evaluatePolicyGate = async (
150→  surreal: Surreal,
151→  identityId: RecordId<"identity">,
152→  workspaceId: RecordId<"workspace">,
153→  intentContext: IntentEvaluationContext,
154→): Promise<PolicyGateResult> => {
155→  // Effect boundary: single DB read
156→  const rawPolicies = await loadActivePolicies(surreal, identityId, workspaceId);
157→
158→  // Pure pipeline
159→  const deduplicated = deduplicatePolicies(rawPolicies);
160→  const sortedRules = collectAndSortRules(deduplicated);
161→  const { evaluatedRules, denyMatched, warnings } = evaluateRulesAgainstContext(
162→    sortedRules,
163→    intentContext,
164→  );
165→
166→  return buildGateResult(evaluatedRules, denyMatched, warnings);
167→};
