 88→// POST /api/workspaces/:workspaceId/learnings
 89→// ---------------------------------------------------------------------------
 90→
 91→type CreateBody = {
 92→  text?: string;
 93→  learning_type?: string;
 94→  priority?: string;
 95→  target_agents?: string[];
 96→};
 97→
 98→async function handleCreateLearning(
 99→  deps: ServerDependencies,
100→  workspaceId: string,
101→  request: Request,
102→): Promise<Response> {
103→  const bodyOrError = await parseJsonBody<CreateBody>(request);
104→  if (isResponse(bodyOrError)) return bodyOrError;
105→  const body = bodyOrError;
106→
107→  // Validate required fields
108→  if (!body.text || typeof body.text !== "string" || body.text.trim().length === 0) {
109→    return jsonError("text is required", 400);
110→  }
111→  if (!body.learning_type || !LEARNING_TYPES.includes(body.learning_type as LearningType)) {
112→    return jsonError(
113→      `learning_type must be one of: ${LEARNING_TYPES.join(", ")}`,
114→      400,
115→    );
116→  }
117→
118→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "learning.create.workspace_resolve.failed");
119→  if (isResponse(workspaceOrError)) return workspaceOrError;
120→  const workspaceRecord = workspaceOrError;
121→
122→  try {
123→    const now = new Date();
124→
125→    // Attempt embedding generation (non-blocking on failure)
126→    let embedding: number[] | undefined;
127→    try {
128→      embedding = await createEmbeddingVector(
129→        deps.embeddingModel,
130→        body.text,
131→        deps.config.embeddingDimension,
132→      );
133→    } catch (error) {
134→      logWarn("learning.create.embedding_failed", "Embedding generation failed — collision detection will be skipped", {
135→        workspaceId,
136→        error: error instanceof Error ? error.message : String(error),
137→      });
138→    }
139→
140→    // Run collision detection before creating the learning (skipped when embedding unavailable)
141→    const collisionResult = await checkCollisions({
142→      surreal: deps.surreal,
143→      model: deps.extractionModel,
144→      workspaceRecord,
145→      learningText: body.text.trim(),
146→      learningEmbedding: embedding,
147→      source: "human",
148→    });
149→
150→    // Determine status: blocked learnings stay pending, otherwise human-created = active
151→    const shouldBlock = collisionResult.hasBlockingCollision;
152→    const learningRecord = await createLearning({
153→      surreal: deps.surreal,
154→      workspaceRecord,
155→      learning: {
156→        text: body.text.trim(),
157→        learningType: body.learning_type as LearningType,
158→        priority: (body.priority as "low" | "medium" | "high") ?? "medium",
159→        targetAgents: body.target_agents ?? [],
160→        source: "human",
161→        ...(shouldBlock ? { forceStatus: "pending_approval" as const } : {}),
162→      },
163→      now,
164→      embedding,
165→    });
166→
167→    const learningId = learningRecord.id as string;
168→
169→    logInfo("learning.created", "Learning created via HTTP", {
170→      workspaceId,
171→      learningId,
172→      learningType: body.learning_type,
173→      hasEmbedding: embedding !== undefined,
174→      collisions: collisionResult.collisions.length,
175→      blocked: shouldBlock,
176→    });
177→
178→    const responseCollisions: CollisionResult[] = collisionResult.collisions;
179→
180→    return jsonResponse({
181→      learningId,
182→      learning: { id: learningId },
183→      collisions: responseCollisions,
184→    }, 201);
185→  } catch (error) {
186→    logError("learning.create.failed", "Failed to create learning", error, { workspaceId });
187→    return jsonError("failed to create learning", 500);
188→  }
189→}
