  1→import { useState, useEffect } from "react";
  2→import { useSearch } from "@tanstack/react-router";
  3→import { useSession } from "../lib/auth-client";
  4→import { getScopeDescription } from "../../shared/scopes";
  5→
  6→type ClientInfo = { client_name: string };
  7→
  8→export function ConsentPage() {
  9→  const { data: session, isPending: sessionPending } = useSession();
 10→  const search = useSearch({ strict: false }) as Record<string, string>;
 11→
 12→  const [clientName, setClientName] = useState<string>();
 13→  const [loading, setLoading] = useState(false);
 14→  const [error, setError] = useState("");
 15→
 16→  const clientId = search.client_id;
 17→  const scopeString = search.scope ?? "";
 18→  const scopes = scopeString.split(" ").filter(Boolean);
 19→
 20→  // Fetch client name for display
 21→  useEffect(() => {
 22→    if (!clientId) return;
 23→    fetch(`/api/auth/oauth-client/${encodeURIComponent(clientId)}`)
 24→      .then((res) => (res.ok ? res.json() : undefined))
 25→      .then((data: ClientInfo | undefined) => {
 26→        if (data?.client_name) setClientName(data.client_name);
 27→      })
 28→      .catch(() => {});
 29→  }, [clientId]);
 30→
 31→  // Redirect to sign-in if not authenticated
 32→  if (!sessionPending && !session) {
 33→    const params = new URLSearchParams(search);
 34→    window.location.href = `/sign-in?redirectTo=${encodeURIComponent(`/consent?${params.toString()}`)}`;
 35→    return undefined;
 36→  }
 37→
 38→  async function handleConsent(accept: boolean) {
 39→    setLoading(true);
 40→    setError("");
 41→
 42→    try {
 43→      const res = await fetch("/api/auth/oauth2/consent", {
 44→        method: "POST",
 45→        headers: { "Content-Type": "application/json" },
 46→        body: JSON.stringify({
 47→          accept,
 48→          ...(accept ? { scope: scopeString } : {}),
 49→          oauth_query: new URLSearchParams(search).toString(),
 50→        }),
 51→      });
 52→
 53→      const data = await res.json() as { url?: string; redirect?: boolean };
 54→
 55→      if (data.url) {
 56→        window.location.href = data.url;
 57→        return;
 58→      }
 59→
 60→      setError("Unexpected response from authorization server");
 61→    } catch (err) {
 62→      setError(err instanceof Error ? err.message : "Consent request failed");
 63→    } finally {
 64→      setLoading(false);
 65→    }
 66→  }
 67→
 68→  if (sessionPending) {
 69→    return (
 70→      <div className="consent-page">
 71→        <div className="consent-card">
 72→          <p className="consent-loading">Loading...</p>
 73→        </div>
 74→      </div>
 75→    );
 76→  }
 77→
 78→  return (
 79→    <div className="consent-page">
 80→      <div className="consent-card">
 81→        <h1 className="consent-title">Authorize Application</h1>
 82→
 83→        <p className="consent-client">
 84→          <strong>{clientName ?? clientId ?? "An application"}</strong> is requesting access to your account.
 85→        </p>
 86→
 87→        {session?.user && (
 88→          <p className="consent-user">
 89→            Signed in as <strong>{session.user.email ?? session.user.name}</strong>
 90→          </p>
 91→        )}
 92→
 93→        {scopes.length > 0 && (
 94→          <div className="consent-scopes">
 95→            <p className="consent-scopes-label">This will allow the application to:</p>
 96→            <ul className="consent-scope-list">
 97→              {scopes.map((scope) => (
 98→                <li key={scope} className="consent-scope-item">
 99→                  <span className="consent-scope-desc">{getScopeDescription(scope)}</span>
100→                  <span className="consent-scope-name">{scope}</span>
101→                </li>
102→              ))}
103→            </ul>
104→          </div>
105→        )}
106→
107→        {error && <p className="consent-error">{error}</p>}
108→
109→        <div className="consent-actions">
110→          <button
111→            type="button"
112→            className="consent-button consent-allow"
113→            onClick={() => handleConsent(true)}
114→            disabled={loading}
115→          >
116→            {loading ? "..." : "Allow"}
117→          </button>
118→          <button
119→            type="button"
120→            className="consent-button consent-deny"
121→            onClick={() => handleConsent(false)}
122→            disabled={loading}
123→          >
124→            Deny
125→          </button>
126→        </div>
127→      </div>
128→    </div>
129→  );
130→}
