194→
195→async function handleListLearnings(
196→  deps: ServerDependencies,
197→  workspaceId: string,
198→  request: Request,
199→): Promise<Response> {
200→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "learning.list.workspace_resolve.failed");
201→  if (isResponse(workspaceOrError)) return workspaceOrError;
202→  const workspaceRecord = workspaceOrError;
203→
204→  try {
205→    const url = new URL(request.url);
206→    const statusParam = url.searchParams.get("status") ?? undefined;
207→    const typeParam = url.searchParams.get("type") ?? undefined;
208→    const agentParam = url.searchParams.get("agent") ?? undefined;
209→
210→    const learnings = await listWorkspaceLearnings({
211→      surreal: deps.surreal,
212→      workspaceRecord,
213→      status: statusParam as LearningStatus | undefined,
214→      learningType: typeParam as LearningType | undefined,
215→      agentType: agentParam,
216→    });
217→
218→    // Return snake_case fields to match HTTP contract
219→    const items = learnings.map((l) => ({
220→      id: l.id,
221→      text: l.text,
222→      learning_type: l.learningType,
223→      status: l.status,
224→      source: l.source,
225→      priority: l.priority,
226→      target_agents: l.targetAgents,
227→      ...(l.suggestedBy ? { suggested_by: l.suggestedBy } : {}),
228→      ...(l.patternConfidence !== undefined ? { pattern_confidence: l.patternConfidence } : {}),
229→      created_at: l.createdAt,
230→      ...(l.approvedAt ? { approved_at: l.approvedAt } : {}),
231→      ...(l.dismissedAt ? { dismissed_at: l.dismissedAt } : {}),
232→      ...(l.dismissedReason ? { dismissed_reason: l.dismissedReason } : {}),
233→      ...(l.deactivatedAt ? { deactivated_at: l.deactivatedAt } : {}),
234→    }));
235→
236→    return jsonResponse({ learnings: items }, 200);
237→  } catch (error) {
238→    logError("learning.list.failed", "Failed to list learnings", error, { workspaceId });
239→    return jsonError("failed to list learnings", 500);
240→  }
241→}
