243→// ---------------------------------------------------------------------------
244→// POST /api/workspaces/:workspaceId/learnings/:learningId/actions
245→// ---------------------------------------------------------------------------
246→
247→type ActionBody = {
248→  action?: string;
249→  reason?: string;
250→  new_text?: string;
251→};
252→
253→async function handleLearningAction(
254→  deps: ServerDependencies,
255→  workspaceId: string,
256→  learningId: string,
257→  request: Request,
258→): Promise<Response> {
259→  const bodyOrError = await parseJsonBody<ActionBody>(request);
260→  if (isResponse(bodyOrError)) return bodyOrError;
261→  const body = bodyOrError;
262→
263→  if (!body.action || !(VALID_ACTIONS as readonly string[]).includes(body.action)) {
264→    return jsonError(
265→      `action must be one of: ${VALID_ACTIONS.join(", ")}`,
266→      400,
267→    );
268→  }
269→
270→  const action = body.action as LearningAction;
271→
272→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "learning.action.workspace_resolve.failed");
273→  if (isResponse(workspaceOrError)) return workspaceOrError;
274→  const workspaceRecord = workspaceOrError;
275→
276→  // Look up the learning
277→  const learningRecord = new RecordId("learning", learningId) as LearningRecord;
278→  let existing: { status: LearningStatus; workspace: RecordId<"workspace", string> } | undefined;
279→  try {
280→    existing = await deps.surreal.select<{
281→      status: LearningStatus;
282→      workspace: RecordId<"workspace", string>;
283→    }>(learningRecord);
284→  } catch {
285→    // select returns undefined if not found
286→  }
287→
288→  if (!existing) {
289→    return jsonError("learning not found", 404);
290→  }
291→
292→  // Verify workspace scope
293→  if ((existing.workspace.id as string) !== (workspaceRecord.id as string)) {
294→    return jsonError("learning not found", 404);
295→  }
296→
297→  // Validate state transition
298→  const transitions = VALID_TRANSITIONS[existing.status];
299→  if (!transitions || !(action in transitions)) {
300→    return jsonError(
301→      `cannot ${action} a learning in status '${existing.status}'`,
302→      409,
303→    );
304→  }
305→
306→  const newStatus = transitions[action];
307→  const now = new Date();
308→
309→  try {
310→    // If approving with new_text, update text first
311→    if (action === "approve" && body.new_text) {
312→      await updateLearningText({
313→        surreal: deps.surreal,
314→        learningRecord,
315→        newText: body.new_text,
316→        now,
317→      });
318→    }
319→
320→    await updateLearningStatus({
321→      surreal: deps.surreal,
322→      workspaceRecord,
323→      learningRecord,
324→      newStatus,
325→      now,
326→      reason: body.reason,
327→    });
328→
329→    logInfo("learning.action.completed", "Learning action completed", {
330→      workspaceId,
331→      learningId,
332→      action,
333→      previousStatus: existing.status,
334→      newStatus,
335→    });
336→
337→    return jsonResponse({ status: newStatus }, 200);
338→  } catch (error) {
339→    logError("learning.action.failed", "Failed to perform learning action", error, {
340→      workspaceId,
341→      learningId,
342→      action,
343→    });
344→    return jsonError("failed to perform action", 500);
345→  }
346→}
