 46→    const [stdout, stderr] = await Promise.all([
 47→      new Response(proc.stdout).text(),
 48→      new Response(proc.stderr).text(),
 49→    ]);
 50→    const exitCode = await proc.exited;
 51→    return { exitCode, stdout, stderr };
 52→  };
