  3→// ---------------------------------------------------------------------------
  4→// Rule Predicates & Conditions
  5→// ---------------------------------------------------------------------------
  6→
  7→export type RulePredicate = {
  8→  field: string;
  9→  operator:
 10→    | "eq"
 11→    | "neq"
 12→    | "lt"
 13→    | "lte"
 14→    | "gt"
 15→    | "gte"
 16→    | "in"
 17→    | "not_in"
 18→    | "exists";
 19→  value: string | number | boolean | string[];
 20→};
 21→
 22→export type RuleCondition = RulePredicate | RulePredicate[];
 23→
 24→// ---------------------------------------------------------------------------
 25→// Policy Domain Types
 26→// ---------------------------------------------------------------------------
 27→
 28→export type PolicyRule = {
 29→  id: string;
 30→  condition: RuleCondition;
 31→  effect: "allow" | "deny";
 32→  priority: number;
 33→};
 34→
 35→export type PolicySelector = {
 36→  workspace?: string;
 37→  agent_role?: string;
 38→  resource?: string;
 39→};
 40→
 41→export type PolicyStatus =
 42→  | "draft"
 43→  | "testing"
 44→  | "active"
 45→  | "deprecated"
 46→  | "superseded";
 47→
 48→export type PolicyRecord = {
 49→  id: RecordId<"policy">;
 50→  title: string;
 51→  description?: string;
 52→  version: number;
 53→  status: PolicyStatus;
 54→  selector: PolicySelector;
 55→  rules: PolicyRule[];
 56→  human_veto_required: boolean;
 57→  max_ttl?: string;
 58→  created_by: RecordId<"identity">;
 59→  workspace: RecordId<"workspace">;
 60→  supersedes?: RecordId<"policy">;
 61→  created_at: Date;
 62→  updated_at?: Date;
 63→};
