 17→// ---------------------------------------------------------------------------
 18→// Identity resolution (session -> person -> identity)
 19→// ---------------------------------------------------------------------------
 20→
 21→type IdentityInfo = {
 22→  identityRecord: RecordId<"identity", string>;
 23→  identityType: string;
 24→};
 25→
 26→async function resolveIdentityFromSession(
 27→  deps: ServerDependencies,
 28→  request: Request,
 29→): Promise<IdentityInfo | Response> {
 30→  const session = await deps.auth.api.getSession({ headers: request.headers });
 31→  if (!session?.user?.id) {
 32→    return jsonError("authentication required", 401);
 33→  }
 34→
 35→  const personRecord = new RecordId("person", session.user.id);
 36→
 37→  const [identityRows] = await deps.surreal.query<[RecordId<"identity", string>[]]>(
 38→    "SELECT VALUE in FROM identity_person WHERE out = $person LIMIT 1;",
 39→    { person: personRecord },
 40→  );
 41→  const identityRecord = identityRows[0] as RecordId<"identity", string> | undefined;
 42→  if (!identityRecord) {
 43→    return jsonError("identity not found for user", 500);
 44→  }
 45→
 46→  const [typeRows] = await deps.surreal.query<[Array<{ type: string }>]>(
 47→    "SELECT type FROM $identity;",
 48→    { identity: identityRecord },
 49→  );
 50→  const identityType = typeRows[0]?.type;
 51→  if (!identityType) {
 52→    return jsonError("identity type not found", 500);
 53→  }
 54→
 55→  return { identityRecord, identityType };
 56→}
