 59→// Shared helpers
 60→// ---------------------------------------------------------------------------
 61→
 62→function isResponse(value: unknown): value is Response {
 63→  return value instanceof Response;
 64→}
 65→
 66→async function resolveWorkspace(
 67→  deps: ServerDependencies,
 68→  workspaceId: string,
 69→  logEvent: string,
 70→): Promise<RecordId<"workspace", string> | Response> {
 71→  try {
 72→    return await resolveWorkspaceRecord(deps.surreal, workspaceId);
 73→  } catch (error) {
 74→    if (error instanceof HttpError) {
 75→      return jsonError(error.message, error.status);
 76→    }
 77→    logError(logEvent, "Failed to resolve workspace", error, { workspaceId });
 78→    return jsonError("failed to resolve workspace", 500);
 79→  }
 80→}
