107→async function requireHumanIdentity(
108→  deps: ServerDependencies,
109→  request: Request,
110→): Promise<IdentityInfo | Response> {
111→  const identityOrError = await resolveIdentityFromSession(deps, request);
112→  if (isResponse(identityOrError)) return identityOrError;
113→
114→  if (isAgentIdentity(identityOrError.identityType)) {
115→    return jsonError("agents cannot modify policies", 403);
116→  }
117→
118→  return identityOrError;
