122→// GET /api/workspaces/:workspaceId/policies
123→// ---------------------------------------------------------------------------
124→
125→async function handleListPolicies(
126→  deps: ServerDependencies,
127→  workspaceId: string,
128→  request: Request,
129→): Promise<Response> {
130→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "policy.list.workspace_resolve.failed");
131→  if (isResponse(workspaceOrError)) return workspaceOrError;
132→  const workspaceRecord = workspaceOrError;
133→
134→  try {
135→    const url = new URL(request.url);
136→    const statusFilter = url.searchParams.get("status") ?? undefined;
137→
138→    const query = statusFilter
139→      ? "SELECT * FROM policy WHERE workspace = $ws AND status = $status ORDER BY created_at DESC;"
140→      : "SELECT * FROM policy WHERE workspace = $ws ORDER BY created_at DESC;";
141→
142→    const params: Record<string, unknown> = { ws: workspaceRecord };
143→    if (statusFilter) params.status = statusFilter;
144→
145→    const [rows] = await deps.surreal.query<[PolicyRecord[]]>(query, params);
146→
147→    const policies = (rows ?? []).map((p) => ({
148→      id: p.id.id as string,
149→      title: p.title,
150→      status: p.status,
151→      version: p.version,
152→      rules_count: p.rules?.length ?? 0,
153→      human_veto_required: p.human_veto_required ?? false,
154→      created_at: p.created_at instanceof Date ? p.created_at.toISOString() : String(p.created_at),
155→      ...(p.updated_at ? {
156→        updated_at: p.updated_at instanceof Date ? p.updated_at.toISOString() : String(p.updated_at),
157→      } : {}),
158→    }));
159→
160→    return jsonResponse({ policies }, 200);
161→  } catch (error) {
162→    logError("policy.list.failed", "Failed to list policies", error, { workspaceId });
163→    return jsonError("failed to list policies", 500);
164→  }
165→}
