177→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "policy.detail.workspace_resolve.failed");
178→  if (isResponse(workspaceOrError)) return workspaceOrError;
179→  const workspaceRecord = workspaceOrError;
180→
181→  try {
182→    const policyRecord = new RecordId("policy", policyId);
183→    const policy = await deps.surreal.select<PolicyRecord>(policyRecord);
184→
185→    if (!policy || (policy.workspace.id as string) !== (workspaceRecord.id as string)) {
186→      return jsonError("policy not found", 404);
187→    }
188→
189→    // Fetch edges
190→    const [governingRows] = await deps.surreal.query<[Array<{ in: RecordId<"identity", string>; created_at: Date }>]>(
191→      "SELECT in, created_at FROM governing WHERE out = $policy;",
192→      { policy: policyRecord },
193→    );
194→    const [protectsRows] = await deps.surreal.query<[Array<{ out: RecordId<"workspace", string>; created_at: Date }>]>(
195→      "SELECT out, created_at FROM protects WHERE in = $policy;",
196→      { policy: policyRecord },
197→    );
198→
199→    return jsonResponse({
200→      policy: {
201→        id: policy.id.id as string,
202→        title: policy.title,
203→        ...(policy.description ? { description: policy.description } : {}),
204→        version: policy.version,
205→        status: policy.status,
206→        selector: policy.selector ?? {},
207→        rules: policy.rules ?? [],
208→        human_veto_required: policy.human_veto_required ?? false,
209→        ...(policy.max_ttl ? { max_ttl: policy.max_ttl } : {}),
210→        ...(policy.supersedes ? { supersedes: policy.supersedes.id as string } : {}),
211→        created_at: policy.created_at instanceof Date ? policy.created_at.toISOString() : String(policy.created_at),
212→        ...(policy.updated_at ? {
213→          updated_at: policy.updated_at instanceof Date ? policy.updated_at.toISOString() : String(policy.updated_at),
214→        } : {}),
215→      },
216→      edges: {
217→        governing: (governingRows ?? []).map((e) => ({
218→          identity_id: e.in.id as string,
219→          created_at: e.created_at instanceof Date ? e.created_at.toISOString() : String(e.created_at),
220→        })),
221→        protects: (protectsRows ?? []).map((e) => ({
222→          workspace_id: e.out.id as string,
223→          created_at: e.created_at instanceof Date ? e.created_at.toISOString() : String(e.created_at),
224→        })),
225→      },
226→      version_chain: [],
227→    }, 200);
228→  } catch (error) {
229→    logError("policy.detail.failed", "Failed to get policy detail", error, { workspaceId, policyId });
230→    return jsonError("failed to get policy detail", 500);
231→  }
232→}
