108→async function requireHumanIdentity(
109→  deps: ServerDependencies,
110→  request: Request,
111→): Promise<IdentityInfo | Response> {
112→  const identityOrError = await resolveIdentityFromSession(deps, request);
113→  if (isResponse(identityOrError)) return identityOrError;
