123→// GET /api/workspaces/:workspaceId/policies
124→// ---------------------------------------------------------------------------
125→
126→async function handleListPolicies(
127→  deps: ServerDependencies,
128→  workspaceId: string,
129→  request: Request,
130→): Promise<Response> {
131→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "policy.list.workspace_resolve.failed");
132→  if (isResponse(workspaceOrError)) return workspaceOrError;
133→  const workspaceRecord = workspaceOrError;
134→
135→  try {
136→    const url = new URL(request.url);
137→    const statusFilter = url.searchParams.get("status") as PolicyStatus | undefined;
138→
139→    const policies = await listWorkspacePolicies(
140→      deps.surreal,
141→      workspaceRecord,
142→      statusFilter || undefined,
143→    );
144→
145→    return jsonResponse({ policies }, 200);
146→  } catch (error) {
147→    logError("policy.list.failed", "Failed to list policies", error, { workspaceId });
148→    return jsonError("failed to list policies", 500);
149→  }
150→}
