152→// ---------------------------------------------------------------------------
153→// GET /api/workspaces/:workspaceId/policies/:policyId
154→// ---------------------------------------------------------------------------
155→
156→async function handlePolicyDetail(
157→  deps: ServerDependencies,
158→  workspaceId: string,
159→  policyId: string,
160→  _request: Request,
161→): Promise<Response> {
162→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "policy.detail.workspace_resolve.failed");
163→  if (isResponse(workspaceOrError)) return workspaceOrError;
164→  const workspaceRecord = workspaceOrError;
165→
166→  try {
167→    const policyRecord = new RecordId("policy", policyId);
168→    const policy = await deps.surreal.select<PolicyRecord>(policyRecord);
169→
170→    if (!policy || (policy.workspace.id as string) !== (workspaceRecord.id as string)) {
171→      return jsonError("policy not found", 404);
172→    }
173→
174→    // Fetch edges
175→    const [governingRows] = await deps.surreal.query<[Array<{ in: RecordId<"identity", string>; created_at: Date }>]>(
176→      "SELECT in, created_at FROM governing WHERE out = $policy;",
177→      { policy: policyRecord },
178→    );
179→    const [protectsRows] = await deps.surreal.query<[Array<{ out: RecordId<"workspace", string>; created_at: Date }>]>(
180→      "SELECT out, created_at FROM protects WHERE in = $policy;",
181→      { policy: policyRecord },
182→    );
183→
184→    return jsonResponse({
185→      policy: {
186→        id: policy.id.id as string,
187→        title: policy.title,
188→        ...(policy.description ? { description: policy.description } : {}),
189→        version: policy.version,
190→        status: policy.status,
191→        selector: policy.selector ?? {},
192→        rules: policy.rules ?? [],
193→        human_veto_required: policy.human_veto_required ?? false,
194→        ...(policy.max_ttl ? { max_ttl: policy.max_ttl } : {}),
195→        ...(policy.supersedes ? { supersedes: policy.supersedes.id as string } : {}),
196→        created_at: policy.created_at instanceof Date ? policy.created_at.toISOString() : String(policy.created_at),
197→        ...(policy.updated_at ? {
198→          updated_at: policy.updated_at instanceof Date ? policy.updated_at.toISOString() : String(policy.updated_at),
199→        } : {}),
200→      },
201→      edges: {
202→        governing: (governingRows ?? []).map((e) => ({
203→          identity_id: e.in.id as string,
204→          created_at: e.created_at instanceof Date ? e.created_at.toISOString() : String(e.created_at),
205→        })),
206→        protects: (protectsRows ?? []).map((e) => ({
207→          workspace_id: e.out.id as string,
208→          created_at: e.created_at instanceof Date ? e.created_at.toISOString() : String(e.created_at),
209→        })),
210→      },
211→      version_chain: [],
212→    }, 200);
213→  } catch (error) {
214→    logError("policy.detail.failed", "Failed to get policy detail", error, { workspaceId, policyId });
215→    return jsonError("failed to get policy detail", 500);
216→  }
217→}
