/**
 * Unit tests for policy creation body validation.
 *
 * Pure function tests -- no DB, no HTTP, no side effects.
 */
import { describe, expect, it } from "bun:test";
import { validatePolicyCreateBody } from "../../app/src/server/policy/policy-validation";

describe("validatePolicyCreateBody", () => {
  // -------------------------------------------------------------------------
  // Title validation
  // -------------------------------------------------------------------------

  it("rejects empty title", () => {
    const result = validatePolicyCreateBody({
      title: "",
      rules: [{
        id: "r1",
        condition: { field: "action", operator: "eq", value: "deploy" },
        effect: "deny",
        priority: 100,
      }],
    });

    expect(result.valid).toBe(false);
    if (!result.valid) {
      expect(result.errors.some((e) => e.includes("title"))).toBe(true);
    }
  });

  it("rejects missing title (undefined cast)", () => {
    const result = validatePolicyCreateBody({
      title: undefined as unknown as string,
      rules: [{
        id: "r1",
        condition: { field: "action", operator: "eq", value: "deploy" },
        effect: "deny",
        priority: 100,
      }],
    });

    expect(result.valid).toBe(false);
    if (!result.valid) {
      expect(result.errors.some((e) => e.includes("title"))).toBe(true);
    }
  });

  it("rejects whitespace-only title", () => {
    const result = validatePolicyCreateBody({
      title: "   ",
      rules: [{
        id: "r1",
        condition: { field: "action", operator: "eq", value: "deploy" },
        effect: "deny",
        priority: 100,
      }],
    });

    expect(result.valid).toBe(false);
    if (!result.valid) {
      expect(result.errors.some((e) => e.includes("title"))).toBe(true);
    }
  });

  // -------------------------------------------------------------------------
  // Rules validation
  // -------------------------------------------------------------------------

  it("rejects empty rules array", () => {
    const result = validatePolicyCreateBody({
      title: "Valid Title",
      rules: [],
    });

    expect(result.valid).toBe(false);
    if (!result.valid) {
      expect(result.errors.some((e) => e.includes("rule"))).toBe(true);
    }
  });

  it("rejects missing rules (undefined cast)", () => {
    const result = validatePolicyCreateBody({
      title: "Valid Title",
      rules: undefined as unknown as [],
    });

    expect(result.valid).toBe(false);
    if (!result.valid) {
      expect(result.errors.some((e) => e.includes("rule"))).toBe(true);
    }
  });

  // -------------------------------------------------------------------------
  // Effect validation
  // -------------------------------------------------------------------------

  it("rejects invalid effect value", () => {
    const result = validatePolicyCreateBody({
      title: "Valid Title",
      rules: [{
        id: "r1",
        condition: { field: "action", operator: "eq", value: "deploy" },
        effect: "maybe" as "allow",
        priority: 100,
      }],
    });

    expect(result.valid).toBe(false);
    if (!result.valid) {
      expect(result.errors.some((e) => e.includes("effect"))).toBe(true);
    }
  });

  // -------------------------------------------------------------------------
  // Predicate structure validation
  // -------------------------------------------------------------------------

  it("rejects predicate missing field", () => {
    const result = validatePolicyCreateBody({
      title: "Valid Title",
      rules: [{
        id: "r1",
        condition: { operator: "eq", value: "deploy" } as unknown,
        effect: "deny",
        priority: 100,
      }],
    });

    expect(result.valid).toBe(false);
  });

  it("rejects predicate missing operator", () => {
    const result = validatePolicyCreateBody({
      title: "Valid Title",
      rules: [{
        id: "r1",
        condition: { field: "action", value: "deploy" } as unknown,
        effect: "deny",
        priority: 100,
      }],
    });

    expect(result.valid).toBe(false);
  });

  it("rejects predicate with invalid operator", () => {
    const result = validatePolicyCreateBody({
      title: "Valid Title",
      rules: [{
        id: "r1",
        condition: { field: "action", operator: "like", value: "deploy" } as unknown,
        effect: "deny",
        priority: 100,
      }],
    });

    expect(result.valid).toBe(false);
  });

  it("rejects completely malformed condition object", () => {
    const result = validatePolicyCreateBody({
      title: "Valid Title",
      rules: [{
        id: "r1",
        condition: { invalid: "structure" } as unknown,
        effect: "deny",
        priority: 100,
      }],
    });

    expect(result.valid).toBe(false);
  });

  // -------------------------------------------------------------------------
  // Valid inputs
  // -------------------------------------------------------------------------

  it("accepts valid body with single rule", () => {
    const result = validatePolicyCreateBody({
      title: "Valid Policy",
      rules: [{
        id: "r1",
        condition: { field: "action_spec.action", operator: "eq", value: "deploy" },
        effect: "deny",
        priority: 100,
      }],
    });

    expect(result.valid).toBe(true);
  });

  it("accepts valid body with array condition (AND logic)", () => {
    const result = validatePolicyCreateBody({
      title: "Valid Policy",
      rules: [{
        id: "r1",
        condition: [
          { field: "action_spec.action", operator: "eq", value: "deploy" },
          { field: "budget_limit.amount", operator: "gt", value: 1000 },
        ],
        effect: "allow",
        priority: 50,
      }],
    });

    expect(result.valid).toBe(true);
  });

  it("accepts all valid operators", () => {
    const operators = ["eq", "neq", "lt", "lte", "gt", "gte", "in", "not_in", "exists"];
    for (const operator of operators) {
      const result = validatePolicyCreateBody({
        title: "Valid Policy",
        rules: [{
          id: "r1",
          condition: { field: "some_field", operator, value: "test" },
          effect: "deny",
          priority: 100,
        }],
      });
      expect(result.valid).toBe(true);
    }
  });
});

/**
 * Pure validation functions for policy creation request bodies.
 *
 * No IO, no DB access -- only data-in, result-out.
 */

// ---------------------------------------------------------------------------
// Result type
// ---------------------------------------------------------------------------

export type ValidationResult =
  | { valid: true }
  | { valid: false; errors: string[] };

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const VALID_OPERATORS = new Set([
  "eq", "neq", "lt", "lte", "gt", "gte", "in", "not_in", "exists",
]);

const VALID_EFFECTS = new Set(["allow", "deny"]);

// ---------------------------------------------------------------------------
// Predicate validation
// ---------------------------------------------------------------------------

function isPlainObject(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

function validatePredicate(predicate: unknown, ruleIndex: number, predicateLabel: string): string[] {
  if (!isPlainObject(predicate)) {
    return [`rule[${ruleIndex}].${predicateLabel}: condition must be an object with field, operator, and value`];
  }

  const errors: string[] = [];

  if (typeof predicate.field !== "string" || predicate.field.trim() === "") {
    errors.push(`rule[${ruleIndex}].${predicateLabel}: predicate must have a non-empty "field" string`);
  }

  if (typeof predicate.operator !== "string" || !VALID_OPERATORS.has(predicate.operator)) {
    errors.push(
      `rule[${ruleIndex}].${predicateLabel}: predicate operator must be one of ${[...VALID_OPERATORS].join(", ")}`,
    );
  }

  if (!("value" in predicate)) {
    errors.push(`rule[${ruleIndex}].${predicateLabel}: predicate must have a "value" property`);
  }

  return errors;
}

function validateCondition(condition: unknown, ruleIndex: number): string[] {
  if (Array.isArray(condition)) {
    if (condition.length === 0) {
      return [`rule[${ruleIndex}].condition: array condition must have at least one predicate`];
    }
    return condition.flatMap((pred, i) =>
      validatePredicate(pred, ruleIndex, `condition[${i}]`),
    );
  }

  return validatePredicate(condition, ruleIndex, "condition");
}

// ---------------------------------------------------------------------------
// Rule validation
// ---------------------------------------------------------------------------

function validateRule(rule: unknown, index: number): string[] {
  if (!isPlainObject(rule)) {
    return [`rule[${index}]: must be an object`];
  }

  const errors: string[] = [];

  // Effect
  if (!VALID_EFFECTS.has(rule.effect as string)) {
    errors.push(`rule[${index}]: effect must be "allow" or "deny"`);
  }

  // Condition
  errors.push(...validateCondition(rule.condition, index));

  return errors;
}

// ---------------------------------------------------------------------------
// Top-level body validation
// ---------------------------------------------------------------------------

type PolicyCreateInput = {
  title: unknown;
  rules: unknown;
};

export function validatePolicyCreateBody(body: PolicyCreateInput): ValidationResult {
  const errors: string[] = [];

  // Title
  if (typeof body.title !== "string" || body.title.trim() === "") {
    errors.push("title is required and must be a non-empty string");
  }

  // Rules
  if (!Array.isArray(body.rules) || body.rules.length === 0) {
    errors.push("at least one rule is required");
  } else {
    for (let i = 0; i < body.rules.length; i++) {
      errors.push(...validateRule(body.rules[i], i));
    }
  }

  return errors.length === 0
    ? { valid: true }
    : { valid: false, errors };
}

