119→  if (params.description) content.description = params.description;
120→  if (params.max_ttl) content.max_ttl = params.max_ttl;
121→
122→  await surreal.query("CREATE $policy CONTENT $content;", {
123→    policy: policyRecord,
124→    content,
125→  });
126→
127→  return { policyId, policyRecord };
128→}
