378→/** A valid policy creation body with one rule. */
379→export function buildPolicyBody(overrides?: Partial<PolicyCreateBody>): PolicyCreateBody {
380→  return {
381→    title: `Test Policy ${crypto.randomUUID().slice(0, 8)}`,
382→    rules: [buildMinimalRule()],
383→    ...overrides,
384→  };
385→}
