 28→async function resolveIdentityFromSession(
 29→  deps: ServerDependencies,
 30→  request: Request,
 31→): Promise<IdentityInfo | Response> {
 32→  const session = await deps.auth.api.getSession({ headers: request.headers });
 33→  if (!session?.user?.id) {
 34→    return jsonError("authentication required", 401);
 35→  }
 36→
 37→  const personRecord = new RecordId("person", session.user.id);
 38→
 39→  const [identityRows] = await deps.surreal.query<[RecordId<"identity", string>[]]>(
 40→    "SELECT VALUE in FROM identity_person WHERE out = $person LIMIT 1;",
 41→    { person: personRecord },
 42→  );
 43→  const identityRecord = identityRows[0] as RecordId<"identity", string> | undefined;
 44→  if (!identityRecord) {
 45→    return jsonError("identity not found for user", 500);
 46→  }
 47→
 48→  const [typeRows] = await deps.surreal.query<[Array<{ type: string }>]>(
 49→    "SELECT type FROM $identity;",
 50→    { identity: identityRecord },
 51→  );
 52→  const identityType = typeRows[0]?.type;
 53→  if (!identityType) {
 54→    return jsonError("identity type not found", 500);
 55→  }
 56→
 57→  return { identityRecord, identityType };
 58→}
