  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { PolicyRecord, PolicyRule, PolicySelector, PolicyStatus } from "./types";
  3→
  4→// --- List Response Types ---
  5→
  6→export type PolicyListItem = {
  7→  id: string;
  8→  title: string;
  9→  status: string;
 10→  version: number;
 11→  rules_count: number;
 12→  human_veto_required: boolean;
 13→  created_at: string;
 14→  updated_at?: string;
 15→};
 16→
 17→// --- Pure Mapping ---
 18→
 19→const formatTimestamp = (value: Date | string): string =>
 20→  value instanceof Date ? value.toISOString() : String(value);
 21→
 22→const toPolicyListItem = (record: PolicyRecord): PolicyListItem => ({
 23→  id: record.id.id as string,
 24→  title: record.title,
 25→  status: record.status,
 26→  version: record.version,
 27→  rules_count: record.rules?.length ?? 0,
 28→  human_veto_required: record.human_veto_required ?? false,
 29→  created_at: formatTimestamp(record.created_at),
 30→  ...(record.updated_at ? { updated_at: formatTimestamp(record.updated_at) } : {}),
 31→});
 32→
 33→// --- Parameter Types ---
 34→
 35→type CreatePolicyParams = {
 36→  title: string;
 37→  description?: string;
 38→  selector?: PolicySelector;
 39→  rules: PolicyRule[];
 40→  human_veto_required?: boolean;
 41→  max_ttl?: string;
 42→  createdBy: RecordId<"identity">;
 43→  workspace: RecordId<"workspace">;
 44→};
 45→
 46→// --- Query Functions ---
 47→
 48→export async function loadActivePolicies(
 49→  surreal: Surreal,
 50→  identityId: RecordId<"identity">,
 51→  workspaceId: RecordId<"workspace">,
 52→): Promise<PolicyRecord[]> {
 53→  const identityResult = await surreal.query<
 54→    [Array<{ policies: PolicyRecord[] }>]
 55→  >(
 56→    `SELECT ->governing->policy.* AS policies FROM $identity;`,
 57→    { identity: identityId },
 58→  );
 59→
 60→  const workspaceResult = await surreal.query<
 61→    [Array<{ policies: PolicyRecord[] }>]
 62→  >(
 63→    `SELECT <-protects<-policy.* AS policies FROM $workspace;`,
 64→    { workspace: workspaceId },
 65→  );
 66→
 67→  const identityPolicies = identityResult[0]?.[0]?.policies ?? [];
 68→  const workspacePolicies = workspaceResult[0]?.[0]?.policies ?? [];
 69→
 70→  // Deduplicate by policy ID and filter active only
 71→  const seen = new Set<string>();
 72→  const result: PolicyRecord[] = [];
 73→  for (const policy of [...identityPolicies, ...workspacePolicies]) {
 74→    const id = policy.id.id as string;
 75→    if (!seen.has(id) && policy.status === "active") {
 76→      seen.add(id);
 77→      result.push(policy);
 78→    }
 79→  }
 80→  return result;
 81→}
