 83→export async function listWorkspacePolicies(
 84→  surreal: Surreal,
 85→  workspace: RecordId<"workspace">,
 86→  statusFilter?: PolicyStatus,
 87→): Promise<PolicyListItem[]> {
 88→  const query = statusFilter
 89→    ? "SELECT * FROM policy WHERE workspace = $ws AND status = $status ORDER BY created_at DESC;"
 90→    : "SELECT * FROM policy WHERE workspace = $ws ORDER BY created_at DESC;";
 91→
 92→  const params: Record<string, unknown> = { ws: workspace };
 93→  if (statusFilter) params.status = statusFilter;
 94→
 95→  const [rows] = await surreal.query<[PolicyRecord[]]>(query, params);
 96→
 97→  return (rows ?? []).map(toPolicyListItem);
 98→}
