154→export async function deprecatePolicy(
155→  surreal: Surreal,
156→  policyId: string,
157→): Promise<void> {
158→  const policyRecord = new RecordId("policy", policyId);
159→
160→  await surreal.query(
161→    `
162→    BEGIN TRANSACTION;
163→      UPDATE $policy SET status = 'deprecated', updated_at = time::now();
164→      DELETE governing WHERE out = $policy;
165→      DELETE protects WHERE in = $policy;
166→    COMMIT TRANSACTION;
167→  `,
168→    { policy: policyRecord },
169→  );
170→}
