 59→      buildPolicyBody({
 60→        title: "Deploy Guard",
 61→        rules: [buildMinimalRule({
 62→          id: "block_deploy",
 63→          condition: { field: "action_spec.action", operator: "eq", value: "deploy" },
 64→          effect: "deny",
 65→          priority: 100,
 66→        })],
 67→      }),
 68→    );
 69→    const { policy_id: policyId } = await createResponse.json() as { policy_id: string };
 70→
 71→    // When admin activates the policy
 72→    const response = await activatePolicyViaApi(
 73→      baseUrl, user.headers, workspace.workspaceId, policyId,
 74→    );
 75→
 76→    // Then the policy status transitions to active
 77→    expect(response.status).toBe(200);
 78→    const body = await response.json() as { status: string };
 79→    expect(body.status).toBe("active");
 80→
 81→    // And the policy detail confirms active status
 82→    const detailResponse = await getPolicyDetail(
 83→      baseUrl, user.headers, workspace.workspaceId, policyId,
 84→    );
 85→    const detail = await detailResponse.json() as PolicyDetailResponse;
 86→    expect(detail.policy.status).toBe("active");
 87→
 88→    // And governing and protects edges are created
