104→
105→    const { policyId } = await createPolicy(surreal, workspace.workspaceId, adminId, {
106→      title: "Already Active",
107→      rules: [{ id: "r1", condition: { field: "action_spec.action", operator: "eq", value: "deploy" }, effect: "deny", priority: 100 }],
108→    });
109→    await activatePolicy(surreal, policyId, adminId, workspace.workspaceId);
110→
111→    // When admin attempts to activate it again
112→    const response = await activatePolicyViaApi(
113→      baseUrl, user.headers, workspace.workspaceId, policyId,
114→    );
115→
116→    // Then the request is rejected
117→    expect(response.status).toBe(409);
118→    const body = await response.json() as { error: string };
119→    expect(body.error).toContain("draft");
120→  }, 120_000);
