324→// ---------------------------------------------------------------------------
325→// Identity Linkage Helpers
326→// ---------------------------------------------------------------------------
327→
328→/**
329→ * Resolves the person record for a session user by calling the auth session
330→ * endpoint, then replaces the identity_person edge so the user resolves to
331→ * the given identity. Used to make a session user appear as an agent identity.
332→ */
333→export async function linkUserToIdentity(
334→  baseUrl: string,
335→  surreal: Surreal,
336→  user: { headers: Record<string, string> },
337→  identityId: string,
338→): Promise<void> {
339→  // Resolve person ID from session
340→  const sessionResponse = await fetch(`${baseUrl}/api/auth/get-session`, {
341→    headers: user.headers,
342→  });
343→  const session = (await sessionResponse.json()) as { user?: { id?: string } };
344→  const personId = session?.user?.id;
345→  if (!personId) throw new Error("Could not resolve person ID from session");
346→
347→  const personRecord = new RecordId("person", personId);
348→  const identityRecord = new RecordId("identity", identityId);
349→
350→  // Remove existing identity_person edges for this person
351→  await surreal.query(
352→    `DELETE identity_person WHERE out = $person;`,
353→    { person: personRecord },
354→  );
355→
356→  // Create new edge from target identity to person
357→  await surreal.query(
358→    `RELATE $identity->identity_person->$person SET added_at = time::now();`,
359→    { identity: identityRecord, person: personRecord },
360→  );
361→}
