130→export async function activatePolicy(
131→  surreal: Surreal,
132→  policyId: string,
133→  creatorId: RecordId<"identity">,
134→  workspaceId: RecordId<"workspace">,
135→): Promise<void> {
136→  const policyRecord = new RecordId("policy", policyId);
137→
138→  await surreal.query(
139→    `
140→    BEGIN TRANSACTION;
141→      UPDATE $policy SET status = 'active', updated_at = time::now();
142→      RELATE $creator->governing->$policy SET created_at = time::now();
143→      RELATE $policy->protects->$workspace SET created_at = time::now();
144→    COMMIT TRANSACTION;
145→  `,
146→    {
147→      policy: policyRecord,
148→      creator: creatorId,
149→      workspace: workspaceId,
150→    },
151→  );
152→}
153→
154→export async function deprecatePolicy(
155→  surreal: Surreal,
156→  policyId: string,
157→): Promise<void> {
158→  const policyRecord = new RecordId("policy", policyId);
159→
160→  await surreal.query(
161→    `
162→    BEGIN TRANSACTION;
163→      UPDATE $policy SET status = 'deprecated', updated_at = time::now();
164→      DELETE governing WHERE out = $policy;
165→      DELETE protects WHERE in = $policy;
166→    COMMIT TRANSACTION;
167→  `,
168→    { policy: policyRecord },
169→  );
170→}
