100→export async function createPolicy(
101→  surreal: Surreal,
102→  params: CreatePolicyParams,
103→): Promise<{ policyId: string; policyRecord: RecordId<"policy"> }> {
104→  const policyId = `policy-${crypto.randomUUID()}`;
105→  const policyRecord = new RecordId("policy", policyId);
106→
107→  const content: Record<string, unknown> = {
108→    title: params.title,
109→    version: 1,
110→    status: "draft",
111→    selector: params.selector ?? {},
112→    rules: params.rules,
113→    human_veto_required: params.human_veto_required ?? false,
114→    created_by: params.createdBy,
115→    workspace: params.workspace,
116→    created_at: new Date(),
117→  };
118→
119→  if (params.description) content.description = params.description;
120→  if (params.max_ttl) content.max_ttl = params.max_ttl;
121→
122→  await surreal.query("CREATE $policy CONTENT $content;", {
123→    policy: policyRecord,
124→    content,
125→  });
126→
127→  return { policyId, policyRecord };
128→}
