 68→async function resolveWorkspace(
 69→  deps: ServerDependencies,
 70→  workspaceId: string,
 71→  logEvent: string,
 72→): Promise<RecordId<"workspace", string> | Response> {
 73→  try {
 74→    return await resolveWorkspaceRecord(deps.surreal, workspaceId);
 75→  } catch (error) {
