109→async function requireHumanIdentity(
110→  deps: ServerDependencies,
111→  request: Request,
112→): Promise<IdentityInfo | Response> {
113→  const identityOrError = await resolveIdentityFromSession(deps, request);
114→  if (isResponse(identityOrError)) return identityOrError;
