154→// GET /api/workspaces/:workspaceId/policies/:policyId
155→// ---------------------------------------------------------------------------
156→
157→async function handlePolicyDetail(
158→  deps: ServerDependencies,
159→  workspaceId: string,
160→  policyId: string,
161→  _request: Request,
162→): Promise<Response> {
163→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "policy.detail.workspace_resolve.failed");
164→  if (isResponse(workspaceOrError)) return workspaceOrError;
165→  const workspaceRecord = workspaceOrError;
166→
167→  try {
168→    const policyRecord = new RecordId("policy", policyId);
169→    const policy = await deps.surreal.select<PolicyRecord>(policyRecord);
170→
171→    if (!policy || (policy.workspace.id as string) !== (workspaceRecord.id as string)) {
172→      return jsonError("policy not found", 404);
173→    }
174→
175→    // Fetch edges
176→    const [governingRows] = await deps.surreal.query<[Array<{ in: RecordId<"identity", string>; created_at: Date }>]>(
177→      "SELECT in, created_at FROM governing WHERE out = $policy;",
178→      { policy: policyRecord },
179→    );
180→    const [protectsRows] = await deps.surreal.query<[Array<{ out: RecordId<"workspace", string>; created_at: Date }>]>(
181→      "SELECT out, created_at FROM protects WHERE in = $policy;",
182→      { policy: policyRecord },
183→    );
184→
185→    return jsonResponse({
186→      policy: {
187→        id: policy.id.id as string,
188→        title: policy.title,
189→        ...(policy.description ? { description: policy.description } : {}),
190→        version: policy.version,
191→        status: policy.status,
192→        selector: policy.selector ?? {},
193→        rules: policy.rules ?? [],
194→        human_veto_required: policy.human_veto_required ?? false,
195→        ...(policy.max_ttl ? { max_ttl: policy.max_ttl } : {}),
196→        ...(policy.supersedes ? { supersedes: policy.supersedes.id as string } : {}),
197→        created_at: policy.created_at instanceof Date ? policy.created_at.toISOString() : String(policy.created_at),
198→        ...(policy.updated_at ? {
199→          updated_at: policy.updated_at instanceof Date ? policy.updated_at.toISOString() : String(policy.updated_at),
200→        } : {}),
201→      },
202→      edges: {
203→        governing: (governingRows ?? []).map((e) => ({
204→          identity_id: e.in.id as string,
205→          created_at: e.created_at instanceof Date ? e.created_at.toISOString() : String(e.created_at),
206→        })),
207→        protects: (protectsRows ?? []).map((e) => ({
208→          workspace_id: e.out.id as string,
209→          created_at: e.created_at instanceof Date ? e.created_at.toISOString() : String(e.created_at),
210→        })),
211→      },
212→      version_chain: [],
213→    }, 200);
214→  } catch (error) {
215→    logError("policy.detail.failed", "Failed to get policy detail", error, { workspaceId, policyId });
216→    return jsonError("failed to get policy detail", 500);
217→  }
218→}
