261→/**
262→ * Creates a human identity with member_of edge for a workspace.
263→ * Returns headers that include session auth for the workspace.
264→ */
265→export async function createHumanIdentityInWorkspace(
266→  surreal: Surreal,
267→  name: string,
268→  workspaceId: string,
269→): Promise<string> {
270→  const identityId = `id-human-${crypto.randomUUID()}`;
271→  const identityRecord = new RecordId("identity", identityId);
272→  const workspaceRecord = new RecordId("workspace", workspaceId);
273→
274→  await surreal.query(`CREATE $identity CONTENT $content;`, {
275→    identity: identityRecord,
276→    content: {
277→      name,
278→      type: "human",
279→      workspace: workspaceRecord,
280→      identity_status: "active",
281→      created_at: new Date(),
282→    },
283→  });
284→
285→  await surreal.query(`RELATE $identity->member_of->$workspace SET added_at = time::now();`, {
286→    identity: identityRecord,
287→    workspace: workspaceRecord,
288→  });
289→
290→  return identityId;
291→}
